#!run 
import {createProxy2} from "@acepad/worker";
import { sibling } from "@acepad/here";
import {proxy} from "@hoge1e3/rpc";
import {findSessionByFile} from "@acepad/files";
import {sessionInfo} from "@acepad/sessions";
import DefaultMap from "@hoge1e3/default-map";
import {setAnnotations,removeAnnotations} from "@acepad/files/annotations.js";
export async function main(){
  const h=this.resolve(".");
  const p=await createProxy2(
    sibling(
        import.meta.url,
        "watchworker.js"));
  const dch=new MessageChannel();
  let m;
  dch.port1.onmessage=({data})=>{
    console.log("diag",data);
    if(m)removeAnnotations(m);
    m=setAnnotations(data.map(d=>{
      const f=this.resolve(d.file);
      const {row,column}=rowcol(f, d.start);
      return {
        file:f,
        row, column,
        text:d.messageText,
        type:"error",
      };
    }));
    /*
    for (let d of data) {
      const f=this.resolve(d.file);
      const s=findSessionByFile(d.file);
      if(!s)continue;
      const si=sessionInfo(s);
      const a=si.tscAnnotaions||[];
      const {row,column}=rowcol(f, d.start);
      s.setAnnotations([{
        row, column,
        text:d.messageText,
        type:"error",
      }]);
    }*/
  };
  await p.main(h.path(), proxy.transfer(dch.port2));
}
function rowcol(file, idx) {
  let lines=file.text().split("\n");
  let row=0;
  for (let line of lines) {
    line+="\n";
    idx-=line.length;
    if (idx<=0) {
      return {row, column:line.length+idx};
    }
    row++;
  }
  return {row,column:0};
}